UI_PATTERNS = [
    {"topic": "responsive_layout", "fact": "Responsive layout: CSS Grid for 2D layouts — display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 1rem. Flexbox for 1D — display: flex; flex-wrap: wrap; gap: 1rem. Container queries: @container (min-width: 400px) { .card { flex-direction: row } }. Mobile-first: start with mobile styles, add min-width breakpoints.", "confidence": 0.95},
    {"topic": "form_patterns", "fact": "Form patterns (React): react-hook-form — const { register, handleSubmit, formState: { errors } } = useForm<FormData>({ resolver: zodResolver(schema) }). Zod schema: z.object({ email: z.string().email(), password: z.string().min(8) }). Controlled with debounced validation. Show inline errors below fields. Disable submit while invalid or loading.", "confidence": 0.95},
    {"topic": "modal_dialog", "fact": "Modal/Dialog pattern: React — const [open, setOpen] = useState(false); <Dialog open={open} onOpenChange={setOpen}><DialogTrigger asChild><Button>Open</Button></DialogTrigger><DialogContent><DialogHeader><DialogTitle>Title</DialogTitle></DialogHeader>Body<DialogFooter><Button onClick={() => setOpen(false)}>Close</Button></DialogFooter></DialogContent></Dialog>. Focus trap, ESC to close, click outside to close.", "confidence": 0.95},
    {"topic": "data_table", "fact": "Data table pattern: TanStack Table (React) — const table = useReactTable({ data, columns, getCoreRowModel: getCoreRowModel(), getSortedRowModel: getSortedRowModel(), getPaginationRowModel: getPaginationRowModel(), getFilteredRowModel: getFilteredRowModel() }). Features: sorting, filtering, pagination, row selection, column resizing. Virtualize large datasets with react-virtual.", "confidence": 0.95},
    {"topic": "toast_notification", "fact": "Toast notification pattern: react-hot-toast — toast.success('Saved!'); toast.error('Failed'); toast.promise(saveData(), { loading: 'Saving...', success: 'Saved!', error: 'Error' }). Sonner alternative: toast('Event created'). Position: top-right. Auto-dismiss: 3-5 seconds. Action button for undo. Stack multiple toasts. Accessible: role='alert' aria-live='assertive'.", "confidence": 0.95},
    {"topic": "infinite_scroll", "fact": "Infinite scroll pattern: IntersectionObserver — const observer = new IntersectionObserver((entries) => { if (entries[0].isIntersecting) loadMore(); }, { threshold: 0.1 }); observer.observe(sentinelRef.current). React Query: useInfiniteQuery({ queryKey: ['items'], queryFn: ({pageParam}) => fetchItems(pageParam), getNextPageParam: (lastPage) => lastPage.nextCursor }).", "confidence": 0.95},
    {"topic": "dark_mode", "fact": "Dark mode pattern: Tailwind — class='dark:bg-gray-900 dark:text-white'. Toggle: document.documentElement.classList.toggle('dark'). System preference: @media (prefers-color-scheme: dark). CSS variables: :root { --bg: white; --text: black } .dark { --bg: #1a1a2e; --text: #e0e0e0 }. Store preference in localStorage. next-themes for Next.js.", "confidence": 0.95},
    {"topic": "sidebar_nav", "fact": "Sidebar navigation pattern: collapsible — const [collapsed, setCollapsed] = useState(false). Width transition: transition-all duration-300. Icon-only when collapsed. Tooltips on icons in collapsed state. Active link highlight. Nested menus with accordion. Mobile: overlay drawer with backdrop. Store collapsed state in localStorage. shadcn/ui Sidebar component.", "confidence": 0.95},
    {"topic": "skeleton_loading", "fact": "Skeleton loading pattern: show placeholder shapes while content loads. CSS: .skeleton { background: linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%); background-size: 200% 100%; animation: shimmer 1.5s infinite; }. React: {loading ? <Skeleton className='h-4 w-[200px]' /> : <Text>{data.title}</Text>}. Better UX than spinners for content-heavy pages.", "confidence": 0.95},
    {"topic": "drag_drop", "fact": "Drag and drop: @dnd-kit (React) — DndContext, SortableContext, useSortable, useDraggable, useDroppable. Sensors: PointerSensor, KeyboardSensor. DragOverlay for custom drag preview. Collision detection: closestCenter, closestCorners, rectIntersection. react-beautiful-dnd (legacy but simpler API). HTML5: draggable='true', ondragstart, ondragover, ondrop.", "confidence": 0.9},
    {"topic": "auth_ui", "fact": "Auth UI pattern: Login form with email/password, social OAuth buttons (Google, GitHub), magic link option. Registration with password strength meter. Protected routes: redirect to /login if unauthenticated. JWT: store in httpOnly cookie (not localStorage). Refresh token rotation. Session display in header with avatar dropdown (profile, settings, logout).", "confidence": 0.95},
    {"topic": "dashboard_layout", "fact": "Dashboard layout: sidebar (nav) + header (breadcrumbs, user menu) + main content. Stat cards row: KPI metrics with trend indicators (up/down arrows, sparklines). Charts: Recharts (React), Chart.js, or D3.js. Data tables with search/filter/sort. Date range picker for filtering. Responsive: sidebar collapses on mobile. Grid layout: grid-cols-1 md:grid-cols-2 lg:grid-cols-4.", "confidence": 0.95},
    {"topic": "command_palette", "fact": "Command palette (Cmd+K): cmdk library — <CommandDialog open={open} onOpenChange={setOpen}><CommandInput placeholder='Type a command...' /><CommandList><CommandGroup heading='Navigation'><CommandItem onSelect={() => router.push('/dashboard')}>Dashboard</CommandItem></CommandGroup></CommandList></CommandDialog>. Global keyboard shortcut. Fuzzy search. Recent items. kbar as alternative.", "confidence": 0.9},
    {"topic": "file_upload", "fact": "File upload UI: react-dropzone — const { getRootProps, getInputProps, isDragActive } = useDropzone({ onDrop, accept: { 'image/*': ['.png','.jpg'] }, maxSize: 5*1024*1024 }). Preview thumbnails before upload. Progress bar during upload. Drag-and-drop zone with dashed border. Multiple file support. Chunked upload for large files. presigned S3 URLs for direct upload.", "confidence": 0.95},
    {"topic": "animation_patterns", "fact": "Animation patterns: Framer Motion (React) — <motion.div initial={{opacity:0, y:20}} animate={{opacity:1, y:0}} exit={{opacity:0}} transition={{duration:0.3}}>. AnimatePresence for mount/unmount animations. Layout animations for reorder. CSS: @keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }. Prefer transform/opacity for 60fps (GPU-accelerated). prefers-reduced-motion media query.", "confidence": 0.95},
]

