def load_all_collections(engine: KnowledgeEngine) -> dict:
    """Load all 8 knowledge collections into the KnowledgeEngine.

    Returns a summary dict with counts per collection.
    """
    collections = {
        "programming_languages": PROGRAMMING_LANGUAGES,
        "framework_patterns": FRAMEWORK_PATTERNS,
        "app_templates": APP_TEMPLATES,
        "database_patterns": DATABASE_PATTERNS,
        "devops_patterns": DEVOPS_PATTERNS,
        "ui_patterns": UI_PATTERNS,
        "testing_patterns": TESTING_PATTERNS,
        "cloud_patterns": CLOUD_PATTERNS,
    }

    summary = {}
    for name, entries in collections.items():
        count = 0
        for entry in entries:
            engine.add_fact(
                topic=entry["topic"],
                fact=entry["fact"],
                confidence=entry.get("confidence", 0.9),
            )
            count += 1
        summary[name] = count

    return summary


def get_collection(name: str) -> list:
    """Get a specific knowledge collection by name."""
    collections = {
        "programming_languages": PROGRAMMING_LANGUAGES,
        "framework_patterns": FRAMEWORK_PATTERNS,
        "app_templates": APP_TEMPLATES,
        "database_patterns": DATABASE_PATTERNS,
        "devops_patterns": DEVOPS_PATTERNS,
        "ui_patterns": UI_PATTERNS,
        "testing_patterns": TESTING_PATTERNS,
        "cloud_patterns": CLOUD_PATTERNS,
    }
    return collections.get(name, [])


def list_collections() -> dict:
    """List all available collections with entry counts."""
    return {
        "programming_languages": len(PROGRAMMING_LANGUAGES),
        "framework_patterns": len(FRAMEWORK_PATTERNS),
        "app_templates": len(APP_TEMPLATES),
        "database_patterns": len(DATABASE_PATTERNS),
        "devops_patterns": len(DEVOPS_PATTERNS),
        "ui_patterns": len(UI_PATTERNS),
        "testing_patterns": len(TESTING_PATTERNS),
        "cloud_patterns": len(CLOUD_PATTERNS),
    }


def search_collections(query: str, limit: int = 10) -> list:
    """Search across all collections for matching entries."""
    query_lower = query.lower()
    results = []
    all_collections = {
        "programming_languages": PROGRAMMING_LANGUAGES,
        "framework_patterns": FRAMEWORK_PATTERNS,
        "app_templates": APP_TEMPLATES,
        "database_patterns": DATABASE_PATTERNS,
        "devops_patterns": DEVOPS_PATTERNS,
        "ui_patterns": UI_PATTERNS,
        "testing_patterns": TESTING_PATTERNS,
        "cloud_patterns": CLOUD_PATTERNS,
    }
    for coll_name, entries in all_collections.items():
        for entry in entries:
            if query_lower in entry["fact"].lower() or query_lower in entry["topic"].lower():
                results.append({
                    "collection": coll_name,
                    "topic": entry["topic"],
                    "fact": entry["fact"],
                    "confidence": entry["confidence"],
                })
    results.sort(key=lambda x: x["confidence"], reverse=True)
    return results[:limit]
